// Aggregate all articles into a single text block for the AI agent
const articles = $input.all();

let summaryText = 'TODAY\'S TOP NEWS ARTICLES (' + articles.length + ' articles from the last 24 hours):\n\n';

for (let i = 0; i < articles.length; i++) {
  const a = articles[i].json;
  summaryText += (i + 1) + '. ' + (a.title || 'No title') + '\n';
  summaryText += '   URL: ' + (a.link || '') + '\n';
  const snippet = (a.snippet || '').substring(0, 250);
  if (snippet) {
    summaryText += '   ' + snippet + '\n';
  }
  summaryText += '\n';
}

return [{ json: { articlesSummary: summaryText, articleCount: articles.length } }];

const raw = String($input.item.json.output || '');

const contentMarker = '---CONTENT---';

let title = 'Untitled';
let content = raw;

const tIdx = raw.indexOf('TITLE:');
if (tIdx !== -1) {
  const afterTitle = raw.substring(tIdx + 6);
  const newline = afterTitle.indexOf('\n');
  title = newline !== -1 ? afterTitle.substring(0, newline).trim() : afterTitle.trim();
}

const contentIdx = raw.indexOf(contentMarker);
if (contentIdx !== -1) {
  content = raw.substring(contentIdx + contentMarker.length).trim();
}

return [{ json: { title, content } }];

const url = query.trim();

if (!url.startsWith('http://') && !url.startsWith('https://')) {
  return 'ERROR: Invalid URL. Must start with http:// or https://';
}

try {
  const html = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    returnFullResponse: false,
    timeout: 15000,
  });

  let text = String(html);

  text = text
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<aside[\s\S]*?<\/aside>/gi, '')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<\/(p|div|h[1-6]|li|tr|br|hr)[^>]*>/gi, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n\s*\n/g, '\n\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  if (text.length > 4000) {
    text = text.substring(0, 4000) + '\n\n[Content truncated]';
  }

  if (text.length < 100) {
    return 'ERROR: Page returned no usable content (likely 404 or paywall). Skip this URL.';
  }

  return text;

} catch (error) {
  return 'ERROR: Could not fetch (' + error.message + '). Skip this URL.';
}
